```python
import csv
import json


def process_rows(rows):
    results = []

    for row in rows:
        name = row['name'].strip().title()
        email = row['email'].strip().lower()
        age = int(row['age'])

        if age >= 18 and '@' in email:
            results.append({
                'name': name,
                'email': email,
                'age': age,
            })

    return results


def process_csv(path):
    with open(path) as f:
        reader = csv.DictReader(f)
        return process_rows(reader)


def process_json(path):
    with open(path) as f:
        data = json.load(f)
        return process_rows(data)
```

The shared row normalization and filtering logic now lives in `process_rows`, while `process_csv` and `process_json` only handle loading data from their respective formats.

